SELECT [Purch_ Price Model Item].[Model Item No_]
FROM ValutazioneMagazzino_Support_DeterminazioneCodiciGiacenti INNER JOIN (ValutazioneMagazzino_GenerazioneVALA_ModelItem_FLAGMOD_SELECT_s0 INNER JOIN (([Purch_ Price Model Item] LEFT JOIN [ValutazioneMagazzino_GenerazioneVALA_ModelItem-PrezziMultipli] ON [Purch_ Price Model Item].[Model Item No_] = [ValutazioneMagazzino_GenerazioneVALA_ModelItem-PrezziMultipli].[Model Item No_]) LEFT JOIN [ValutazioneMagazzino_GenerazioneVALA_ModelItem-VALB-GiaPresenti] ON [Purch_ Price Model Item].[Model Item No_] = [ValutazioneMagazzino_GenerazioneVALA_ModelItem-VALB-GiaPresenti].[Model Item No_]) ON ValutazioneMagazzino_GenerazioneVALA_ModelItem_FLAGMOD_SELECT_s0.No_ = [Purch_ Price Model Item].[Model Item No_]) ON ValutazioneMagazzino_Support_DeterminazioneCodiciGiacenti.[Model Item No_] = ValutazioneMagazzino_GenerazioneVALA_ModelItem_FLAGMOD_SELECT_s0.No_
WHERE ((([ValutazioneMagazzino_GenerazioneVALA_ModelItem-VALB-GiaPresenti].[Model Item No_]) Is Null) AND (([ValutazioneMagazzino_GenerazioneVALA_ModelItem-PrezziMultipli].[Model Item No_]) Is Null));

